// src/pages/Register.jsx

import { useState } from "react";
import axios from "axios";

export default function Register() {

  const [form, setForm] =
    useState({

      role: "customer",

      skills: []

    });

  const jobs = [

    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"

  ];

  const handleSkills = (e) => {

    const values = Array.from(

      e.target.selectedOptions,

      option => option.value

    );

    setForm({

      ...form,

      skills: values

    });
  };

  const register = async () => {

    try {

      const res = await axios.post(

        "http://localhost:5000/api/auth/register",

        form

      );

      localStorage.setItem(

        "user",

        JSON.stringify(res.data.user)

      );

      if (form.role === "customer") {

        window.location =
          "/customer-dashboard";

      } else {

        window.location =
          "/labour-dashboard";

      }

    } catch (err) {

      alert(

        err.response?.data?.message ||

        "Registration Failed"

      );
    }
  };

  return (

    <div style={styles.page}>

      {/* ORANGE GLOW */}

      <div style={styles.glow1}></div>
      <div style={styles.glow2}></div>

      {/* REGISTER CARD */}

      <div style={styles.card}>

        <h1 style={styles.brand}>
          DailyMajdoor
        </h1>

        <h2 style={styles.title}>
          Register
        </h2>

        <p style={styles.subtitle}>
          Create your account
        </p>

        <div style={styles.field}>

          <select
            style={styles.input}
            onChange={(e) =>
              setForm({
                ...form,
                role: e.target.value
              })
            }
          >

            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

        </div>

        <div style={styles.field}>

          <input
            style={styles.input}
            placeholder="Full Name"
            onChange={(e) =>
              setForm({
                ...form,
                name: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) =>
              setForm({
                ...form,
                email: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <input
            type="password"
            style={styles.input}
            placeholder="Password"
            onChange={(e) =>
              setForm({
                ...form,
                password: e.target.value
              })
            }
          />

        </div>

        <div style={styles.field}>

          <input
            style={styles.input}
            placeholder="Phone"
            onChange={(e) =>
              setForm({
                ...form,
                phone: e.target.value
              })
            }
          />

        </div>

        <div style={styles.fieldRow}>

          <input
            style={styles.smallInput}
            placeholder="City"
            onChange={(e) =>
              setForm({
                ...form,
                city: e.target.value
              })
            }
          />

          <input
            style={styles.smallInput}
            placeholder="Area"
            onChange={(e) =>
              setForm({
                ...form,
                area: e.target.value
              })
            }
          />

        </div>

        {form.role === "labour" && (

          <div style={styles.field}>

            <select
              multiple
              style={styles.multi}
              onChange={handleSkills}
            >

              {jobs.map((job, index) => (

                <option
                  key={index}
                  value={job}
                >
                  {job}
                </option>

              ))}

            </select>

          </div>

        )}

        <button
          style={styles.button}
          onClick={register}
        >
          Create Account
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
  minHeight: "100vh",
  background: "#0f172a",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  position: "relative",
  overflow: "hidden",
  fontFamily: "Arial",
  margin: 0
},

  glow1: {
    position: "absolute",
    width: "260px",
    height: "260px",
    borderRadius: "50%",
    background: "#f97316",
    filter: "blur(120px)",
    top: "-80px",
    left: "-80px",
    opacity: 0.35
  },

  glow2: {
    position: "absolute",
    width: "220px",
    height: "220px",
    borderRadius: "50%",
    background: "#fb923c",
    filter: "blur(100px)",
    bottom: "-80px",
    right: "-80px",
    opacity: 0.3
  },

  // REPLACE ONLY THIS CARD STYLE

card: {
  width: "340px",
  background: "#111827",
  border: "2px solid #f97316",
  borderRadius: "20px",
  padding: "22px",
  position: "relative",
  zIndex: 2,
  boxShadow:
    "0 10px 35px rgba(0,0,0,0.45)"
},

  brand: {
    textAlign: "center",
    color: "#fb923c",
    margin: 0,
    marginBottom: "12px",
    fontSize: "26px"
  },

  title: {
    textAlign: "center",
    color: "white",
    margin: 0,
    fontSize: "22px"
  },

  subtitle: {
    textAlign: "center",
    color: "#9ca3af",
    marginTop: "6px",
    marginBottom: "18px",
    fontSize: "12px"
  },

  field: {
    marginBottom: "12px"
  },

  fieldRow: {
    display: "flex",
    gap: "10px",
    marginBottom: "12px"
  },

  input: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "13px"
  },

  smallInput: {
    width: "50%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    boxSizing: "border-box",
    outline: "none",
    fontSize: "13px"
  },

  multi: {
    width: "100%",
    height: "85px",
    borderRadius: "10px",
    border: "1px solid #f97316",
    background: "#1f2937",
    color: "white",
    padding: "10px",
    fontSize: "13px",
    outline: "none"
  },

  button: {
    width: "100%",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    padding: "12px",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "bold",
    marginTop: "6px",
    fontSize: "14px"
  }

};
